import{_ as e,o as a,c as t,O as o}from"./chunks/framework.bdcb0ee1.js";const g=JSON.parse('{"title":"Topic Labels","description":"","frontmatter":{},"headers":[],"relativePath":"administration/config/topic-labels.md","filePath":"administration/config/topic-labels.md","lastUpdated":1773166715000}'),l={name:"administration/config/topic-labels.md"},i=o('<h1 id="topic-labels" tabindex="-1">Topic Labels <a class="header-anchor" href="#topic-labels" aria-label="Permalink to &quot;Topic Labels&quot;">​</a></h1><p>Topic labels let you tag discussions with short pieces of text that help categorize or highlight their purpose. They appear next to the topic title in forum topic lists.</p><p>Labels are most commonly used for things like:</p><ul><li>Marking threads as [Resolved], [Request], [In Progress]</li><li>Highlighting important post types like [Bug] or [Idea]</li><li>Structuring support forums with tags like [Mac], [Windows], [Mobile]</li></ul><p>You can manage topic labels from the <strong>Board Config</strong> section of the Admin Control Panel.</p><h2 id="how-labels-work" tabindex="-1">How Labels Work <a class="header-anchor" href="#how-labels-work" aria-label="Permalink to &quot;How Labels Work&quot;">​</a></h2><p>Labels are added and edited by users or moderators through the <strong>&quot;Edit Topic Title&quot;</strong> option on the frontend. Only one label can be applied to a topic at a time.</p><p>Labels are shown in the topic list, right before the topic title.</p><h2 id="adding-a-label" tabindex="-1">Adding a Label <a class="header-anchor" href="#adding-a-label" aria-label="Permalink to &quot;Adding a Label&quot;">​</a></h2><p>To create a new label:</p><ul><li><strong>Content</strong>: The label text. BBCode is supported.</li><li><strong>Available in all forums</strong>: Toggle this to make the label usable in every forum (global). When disabled, you can pick which specific forums should allow this label.</li><li><strong>Available forums</strong>: A list of forums where the label can be used (only shown when the label is not global).</li></ul><img width="1941" height="1001" alt="image" src="https://github.com/user-attachments/assets/9d7f8f3f-cfc7-4eb8-b813-b6d456326b19"><h2 id="upcoming-features" tabindex="-1">Upcoming Features <a class="header-anchor" href="#upcoming-features" aria-label="Permalink to &quot;Upcoming Features&quot;">​</a></h2><ul><li>Topic labels will soon be <strong>filterable per forum</strong>, allowing users to quickly view only threads with a specific label.</li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Only one label can be assigned to a topic.</li><li>Labels are visible to all users and can help enforce or suggest forum structure.</li><li>Moderators can change labels on any topic.</li></ul>',16),s=[i];function r(n,c,h,d,p,u){return a(),t("div",null,s)}const m=e(l,[["render",r]]);export{g as __pageData,m as default};
